import io
import os
import json
import torch
import torch.nn.functional as F
from PIL import Image
from fastapi import FastAPI, File, UploadFile, HTTPException
from fastapi.responses import JSONResponse

DEVICE = os.getenv("DEVICE", "cpu")
MODEL_PATH = os.getenv("MODEL_PATH", "model.pt")
CLASSES_PATH = os.getenv("CLASSES_PATH", "")
INPUT_TENSOR_KEY = os.getenv("INPUT_TENSOR_KEY", "")
OUTPUT_TENSOR_KEY = os.getenv("OUTPUT_TENSOR_KEY", "")
MAX_IMAGE_BYTES = int(os.getenv("MAX_IMAGE_BYTES", "0"))

app = FastAPI()

model = None
classes = None

def _load_classes():
    global classes
    if CLASSES_PATH and os.path.exists(CLASSES_PATH):
        with open(CLASSES_PATH, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict) and "classes" in data:
            data = data["classes"]
        if not isinstance(data, list):
            data = list(data)
        classes = data
    else:
        classes = None

def _load_model():
    global model
    obj = torch.load(MODEL_PATH, map_location=DEVICE)
    if isinstance(obj, torch.nn.Module):
        model = obj
    elif isinstance(obj, dict):
        if "model" in obj and isinstance(obj["model"], torch.nn.Module):
            model = obj["model"]
        elif "state_dict" in obj:
            raise RuntimeError("MODEL_PATH contains a state_dict; provide a scripted/serialized model instead.")
        else:
            raise RuntimeError("Unsupported model checkpoint format.")
    else:
        model = obj
    if hasattr(model, "eval"):
        model.eval()
    return model

@app.on_event("startup")
def startup():
    _load_classes()
    _load_model()

def _to_tensor_no_preprocess(img: Image.Image) -> torch.Tensor:
    b = img.tobytes()
    x = torch.frombuffer(b, dtype=torch.uint8)
    x = x.reshape((img.height, img.width, len(img.getbands())))
    x = x.permute(2, 0, 1).contiguous()
    x = x.unsqueeze(0)
    return x

def _extract_logits(output):
    if isinstance(output, torch.Tensor):
        return output
    if isinstance(output, (list, tuple)) and len(output) > 0:
        if isinstance(output[0], torch.Tensor):
            return output[0]
    if isinstance(output, dict):
        if OUTPUT_TENSOR_KEY and OUTPUT_TENSOR_KEY in output and isinstance(output[OUTPUT_TENSOR_KEY], torch.Tensor):
            return output[OUTPUT_TENSOR_KEY]
        for v in output.values():
            if isinstance(v, torch.Tensor):
                return v
    raise RuntimeError("Model output type unsupported; cannot extract logits tensor.")

@app.post("/predict")
async def predict(file: UploadFile = File(...)):
    if not file:
        raise HTTPException(status_code=400, detail="missing file")

    raw = await file.read()
    if MAX_IMAGE_BYTES > 0 and len(raw) > MAX_IMAGE_BYTES:
        raise HTTPException(status_code=413, detail="payload too large")

    img = Image.open(io.BytesIO(raw))
    x = _to_tensor_no_preprocess(img).to(DEVICE)

    with torch.inference_mode():
        if INPUT_TENSOR_KEY:
            out = model(**{INPUT_TENSOR_KEY: x})
        else:
            out = model(x)

    logits = _extract_logits(out)
    if logits.dim() == 1:
        logits = logits.unsqueeze(0)

    probs = F.softmax(logits, dim=-1)
    conf, idx = torch.max(probs, dim=-1)

    pred_idx = int(idx[0].item())
    confidence = float(conf[0].item())

    pred_class = classes[pred_idx] if classes and 0 <= pred_idx < len(classes) else pred_idx

    return JSONResponse(
        {
            "predicted_class": pred_class,
            "confidence": confidence,
            "class_index": pred_idx,
        }
    )

@app.get("/health")
def health():
    return {"status": "ok", "device": DEVICE, "model_path": MODEL_PATH}